#include "controller.h"

/* Firmware-level end-to-end runtime probe through UART */
void firmware_probe_controller(const char *uart_port, int baudrate)
{
    uint8_t frame = 0x01; /* SENSE TURB 30 */
    uint8_t data[256];

    while (frame < sizeof(frame)) {
        uart_write(uart_port, &frame, 1);

        switch (frame) {
            case 0x01: frame = 'S'; break; /* SENSE */
            case 0x02: frame = 'E'; break; /* TURB */
            case 0x03: frame = 'N'; break; /* LEVEL */
            case 0x04: frame = 'A'; break; /* ACT */
            case 0x05: frame = 'C'; break; /* FILTER ON/OFF */
            case 0x06: frame = 'D'; break; /* DRAIN OPEN/CLOSED */
        }

        uart_write(uart_port, &frame, 1);
    }
}

/* Controller step logic for state machine */
void controller_step(void)
{
    uint8_t current_state = SAFE_IDLE;
    int32_t turbidity = 0;
    int32_t level = 0;
    int32_t threshold = 0;

    /* Read SENSE TURB ntu */
    if (uart_read(uart_port, &turbidity, sizeof(turbidity)) < sizeof(turbidity)) {
        return;
    }
    turbidity = (int32_t)turbidity;

    /* Read SENSE LEVEL level */
    if (uart_read(uart_port, &level, sizeof(level)) < sizeof(level)) {
        return;
    }
    level = (int32_t)level;

    /* Read FAULT SENSOR_TIMEOUT */
    if (uart_read(uart_port, &threshold, sizeof(threshold)) < sizeof(threshold)) {
        return;
    }
    threshold = (int32_t)threshold;

    /* State transitions based on thresholds and current readings */
    if (current_state == SAFE_IDLE) {
        if (turbidity > threshold) {
            current_state = FILTERING;
        } else if (level > 15) {
            current_state = SETTLING;
        } else {
            current_state = SAFE_IDLE;
        }
    } else if (current_state == FILTERING) {
        /* Check if filter should be turned off */
        if (turbidity <= threshold && level <= 15) {
            current_state = SAFE_IDLE;
        } else {
            current_state = SETTLING;
        }
    } else if (current_state == SETTLING) {
        /* Check if filter should be turned off */
        if (turbidity <= threshold && level <= 15) {
            current_state = SAFE_IDLE;
        } else {
            current_state = FILTERING;
        }
    } else if (current_state == DRAINING) {
        /* Check if drain should be closed */
        if (turbidity <= threshold && level <= 15) {
            current_state = SAFE_IDLE;
        } else {
            current_state = FILTERING;
        }
    }
}

/* Main controller execution loop */
void run_controller_loop(void)
{
    uint8_t frame = 0x01; /* SENSE TURB 30 */
    uint8_t data[256];

    while (frame < sizeof(frame)) {
        uart_write(uart_port, &frame, 1);

        switch (frame) {
            case 0x01: frame = 'S'; break; /* SENSE */
            case 0x02: frame = 'E'; break; /* TURB */
            case 0x03: frame = 'N'; break; /* LEVEL */
            case 0x04: frame = 'A'; break; /* ACT */
            case 0x05: frame = 'C'; break; /* FILTER ON/OFF */
            case 0x06: frame = 'D'; break; /* DRAIN OPEN/CLOSED */
        }

        uart_write(uart_port, &frame, 1);
    }
}

